Here are the comparison assertions you should use and a complete test class:

**Key MSTest comparison assertions:**

| Assertion | Purpose |
|-----------|---------|
| `Assert.IsGreaterThan(lowerBound, actual)` | Value exceeds a minimum |
| `Assert.IsLessThan(upperBound, actual)` | Value is below a maximum |
| `Assert.IsInRange(actual, low, high)` | Value falls within bounds |

**Complete test class:**

```csharp
using Contoso.Scoring;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    // CalculatePercentage tests

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 10, 0.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        var result = _calculator.CalculatePercentage(correct, total);
        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void CalculatePercentage_Result_IsInValidRange()
    {
        var result = _calculator.CalculatePercentage(8, 10);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void CalculatePercentage_MajorityCorrect_IsGreaterThan50()
    {
        var result = _calculator.CalculatePercentage(6, 10);
        Assert.IsGreaterThan(50.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_MinorityCorrect_IsLessThan50()
    {
        var result = _calculator.CalculatePercentage(4, 10);
        Assert.IsLessThan(50.0, result);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // GetGrade boundary tests

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.9, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.9, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(double percentage, string expected)
    {
        var result = _calculator.GetGrade(percentage);
        Assert.AreEqual(expected, result);
    }

    // NormalizeScore tests

    [TestMethod]
    public void NormalizeScore_HalfOfMax_Returns50()
    {
        var result = _calculator.NormalizeScore(50, 100);
        Assert.AreEqual(50.0, result);
    }

    [TestMethod]
    public void NormalizeScore_Result_IsInRange0To100()
    {
        var result = _calculator.NormalizeScore(75, 200);
        Assert.IsInRange(result, 0.0, 100.0);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calculator.NormalizeScore(150, 100);
        Assert.AreEqual(100.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NonZeroRaw_IsGreaterThanZero()
    {
        var result = _calculator.NormalizeScore(1, 100);
        Assert.IsGreaterThan(0.0, result);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50, 0));
    }
}
```

**Summary of the assertions used:**

- **`Assert.IsInRange(actual, low, high)`** — validates percentages/scores stay within 0–100
- **`Assert.IsGreaterThan(lowerBound, actual)`** — confirms a score exceeds a threshold
- **`Assert.IsLessThan(upperBound, actual)`** — confirms a score is below a threshold
- **`Assert.ThrowsExactly<T>`** — validates argument guard clauses
- **`[DataRow]`** at grade boundaries — tests exact boundary transitions (90, 80, 70, 60 and just below each)

These require **MSTest 3.8+**. Use either the `MSTest.Sdk` or the `MSTest` metapackage.
